const SSO_API = "https://sso.erldc.in:5000";
const SESSION_WARNING_THRESHOLD = 5 * 60; // show warning when <5 min remain

export default function Dashboard() {
	const navigate = useNavigate();
	const [query, setQuery] = useState("");
	const [activeCategory, setActiveCategory] = useState("All");
	const [isCheckingSession, setIsCheckingSession] = useState(true);
	const [sessionExpiresAt, setSessionExpiresAt] = useState(null);
	const [userDepartment, setUserDepartment] = useState(null);
	const [userName, setUserName] = useState("");
	const [now, setNow] = useState(() => new Date());
	const [currentUserId, setCurrentUserId] = useState("");
	const [activeUsers, setActiveUsers] = useState([]);
	const [customApps, setCustomApps] = useState(() => {
		const saved = localStorage.getItem("sso_custom_apps");
		return saved ? JSON.parse(saved) : [];
	});
	const [showAddAppDialog, setShowAddAppDialog] = useState(false);
	const [newAppTitle, setNewAppTitle] = useState("");
	const [newAppDesc, setNewAppDesc] = useState("");
	const [newAppUrl, setNewAppUrl] = useState("");
	const [newAppAccent, setNewAppAccent] = useState("blue");
	const [newAppIcon, setNewAppIcon] = useState("pi pi-box");
	const [newAppImage, setNewAppImage] = useState("");

	// Admin Deletion & Editing States
	const [deletedStaticTitles, setDeletedStaticTitles] = useState(() => {
		const saved = localStorage.getItem("sso_deleted_static_apps");
		return saved ? JSON.parse(saved) : [];
	});
	const [modifiedStaticApps, setModifiedStaticApps] = useState(() => {
		const saved = localStorage.getItem("sso_modified_static_apps");
		return saved ? JSON.parse(saved) : [];
	});

	const [editingApp, setEditingApp] = useState(null);
	const [showEditAppDialog, setShowEditAppDialog] = useState(false);
	const [editAppTitle, setEditAppTitle] = useState("");
	const [editAppDesc, setEditAppDesc] = useState("");
	const [editAppUrl, setEditAppUrl] = useState("");
	const [editAppAccent, setEditAppAccent] = useState("blue");
	const [editAppIcon, setEditAppIcon] = useState("pi pi-box");
	const [editAppImage, setEditAppImage] = useState("");
	const [editAppOriginalTitle, setEditAppOriginalTitle] = useState("");

	// Custom Quick Links States
	const [customQuickLinks, setCustomQuickLinks] = useState(() => {
		const saved = localStorage.getItem("sso_custom_quick_links");
		return saved ? JSON.parse(saved) : [];
	});
	const [showAddQuickLinkDialog, setShowAddQuickLinkDialog] = useState(false);
	const [newQuickLinkLabel, setNewQuickLinkLabel] = useState("");
	const [newQuickLinkUrl, setNewQuickLinkUrl] = useState("");
	const [newQuickLinkTone, setNewQuickLinkTone] = useState("teal");
	const [newQuickLinkIcon, setNewQuickLinkIcon] = useState("pi pi-link");

	const handleImageChange = (e) => {
		const file = e.target.files && e.target.files[0];
		if (!file) return;

		const reader = new FileReader();
		reader.onloadend = () => {
			setNewAppImage(reader.result);
		};
		reader.readAsDataURL(file);
	};

	const handleAddApp = (e) => {
		if (e) e.preventDefault();
		if (!newAppTitle || !newAppUrl) {
			return;
		}

		const newApp = {
			imageName: newAppImage || "GILogo.png",
			linkTo: newAppUrl,
			title: newAppTitle,
			desc: newAppDesc,
			category: "Custom",
			accent: newAppAccent,
			icon: newAppIcon,
		};

		const updatedApps = [...customApps, newApp];
		setCustomApps(updatedApps);
		localStorage.setItem("sso_custom_apps", JSON.stringify(updatedApps));
		saveWorkspaceData({ custom_apps: updatedApps });

		// Reset form state
		setNewAppTitle("");
		setNewAppDesc("");
		setNewAppUrl("");
		setNewAppAccent("blue");
		setNewAppIcon("pi pi-box");
		setNewAppImage("");
		setShowAddAppDialog(false);
	};

	const handleDeleteApp = (app) => {
		const isConfirmed = window.confirm(`Are you sure you want to delete the application "${app.title}"?`);
		if (!isConfirmed) return;

		const isStatic = applications.some((staticApp) => staticApp.title === app.title || (app.originalTitle && staticApp.title === app.originalTitle));

		if (isStatic) {
			const originalTitle = app.originalTitle || app.title;
			const newDeleted = [...deletedStaticTitles, originalTitle];
			setDeletedStaticTitles(newDeleted);
			localStorage.setItem("sso_deleted_static_apps", JSON.stringify(newDeleted));
			saveWorkspaceData({ deleted_static_apps: newDeleted });
		} else {
			const newCustom = customApps.filter((customApp) => customApp.title !== app.title);
			setCustomApps(newCustom);
			localStorage.setItem("sso_custom_apps", JSON.stringify(newCustom));
			saveWorkspaceData({ custom_apps: newCustom });
		}
	};

	const handleStartEdit = (app) => {
		const isStatic = applications.some((staticApp) => staticApp.title === app.title || (app.originalTitle && staticApp.title === app.originalTitle));
		
		setEditingApp(app);
		setEditAppTitle(app.title);
		setEditAppDesc(app.desc);
		setEditAppUrl(app.linkTo);
		setEditAppAccent(app.accent || "blue");
		setEditAppIcon(app.icon || "pi pi-box");
		setEditAppImage(app.imageName || "");
		setEditAppOriginalTitle(isStatic ? (app.originalTitle || app.title) : "");
		setShowEditAppDialog(true);
	};

	const handleEditImageChange = (e) => {
		const file = e.target.files && e.target.files[0];
		if (!file) return;

		const reader = new FileReader();
		reader.onloadend = () => {
			setEditAppImage(reader.result);
		};
		reader.readAsDataURL(file);
	};

	const handleSaveEdit = (e) => {
		if (e) e.preventDefault();
		if (!editAppTitle || !editAppUrl) return;

		const isStatic = !!editAppOriginalTitle;

		if (isStatic) {
			const updatedApp = {
				originalTitle: editAppOriginalTitle,
				title: editAppTitle,
				desc: editAppDesc,
				linkTo: editAppUrl,
				accent: editAppAccent,
				icon: editAppIcon,
				imageName: editAppImage || "GILogo.png",
				category: editingApp.category
			};

			const otherModified = modifiedStaticApps.filter(
				(mod) => mod.originalTitle !== editAppOriginalTitle
			);
			const newModified = [...otherModified, updatedApp];
			setModifiedStaticApps(newModified);
			localStorage.setItem("sso_modified_static_apps", JSON.stringify(newModified));
			saveWorkspaceData({ modified_static_apps: newModified });
		} else {
			const updatedApp = {
				title: editAppTitle,
				desc: editAppDesc,
				linkTo: editAppUrl,
				accent: editAppAccent,
				icon: editAppIcon,
				imageName: editAppImage || "GILogo.png",
				category: "Custom"
			};

			const newCustom = customApps.map((customApp) => 
				customApp.title === editingApp.title ? updatedApp : customApp
			);
			setCustomApps(newCustom);
			localStorage.setItem("sso_custom_apps", JSON.stringify(newCustom));
			saveWorkspaceData({ custom_apps: newCustom });
		}

		// Reset form and close dialog
		setEditingApp(null);
		setEditAppTitle("");
		setEditAppDesc("");
		setEditAppUrl("");
		setEditAppAccent("blue");
		setEditAppIcon("pi pi-box");
		setEditAppImage("");
		setEditAppOriginalTitle("");
		setShowEditAppDialog(false);
	};

	// Dynamic mapping of applications to inject the actual token for CRMS-ERLDC
	const token = localStorage.getItem("token");
	const mappedApplications = useMemo(() => {
		const activeStaticApps = applications.filter(
			(app) => !deletedStaticTitles.includes(app.title)
		);

		return activeStaticApps.map((app) => {
			const modification = modifiedStaticApps.find(
				(mod) => mod.originalTitle === app.title
			);

			let resolvedApp = modification ? { ...app, ...modification } : app;

			if (app.title === "CRMS-ERLDC") {
				return {
					...resolvedApp,
					linkTo: token
						? `https://crms.erldc.in/Codebook/accounts/login/?token=${encodeURIComponent(token)}`
						: resolvedApp.linkTo,
				};
			}
			return resolvedApp;
		});
	}, [token, deletedStaticTitles, modifiedStaticApps]);

	const allApplications = useMemo(() => {
		return [...mappedApplications, ...customApps];
	}, [mappedApplications, customApps]);

	const handleAddQuickLink = (e) => {
		if (e) e.preventDefault();
		if (!newQuickLinkLabel || !newQuickLinkUrl) return;

		const newLink = {
			label: newQuickLinkLabel,
			url: newQuickLinkUrl,
			tone: newQuickLinkTone,
			icon: newQuickLinkIcon,
		};

		const updatedLinks = [...customQuickLinks, newLink];
		setCustomQuickLinks(updatedLinks);
		localStorage.setItem("sso_custom_quick_links", JSON.stringify(updatedLinks));
		saveWorkspaceData({ custom_quick_links: updatedLinks });

		// Reset form and close dialog
		setNewQuickLinkLabel("");
		setNewQuickLinkUrl("");
		setNewQuickLinkTone("teal");
		setNewQuickLinkIcon("pi pi-link");
		setShowAddQuickLinkDialog(false);
	};

	const allQuickLinks = useMemo(() => {
		return [...quickLinks, ...customQuickLinks];
	}, [customQuickLinks]);

	// Password expiry for the logged-in user
	const [pwdExpiry, setPwdExpiry] = useState(null); // { daysRemaining, neverExpires }
	const [pwdBannerDismissed, setPwdBannerDismissed] = useState(false);

	// Session expiry warning modal
	const [showSessionWarning, setShowSessionWarning] = useState(false);
	const sessionWarnedRef = useRef(false);

	// Employee Directory States
	const [showEmpDirectory, setShowEmpDirectory] = useState(false);
	const [empData, setEmpData] = useState([]);
	const [filters, setFilters] = useState({
		global: { value: null, matchMode: FilterMatchMode.CONTAINS },
	});
	const [globalFilterValue, setGlobalFilterValue] = useState("");

	const empTableData = useMemo(() => {
		return empData.map((emp) => ({
			...emp,
			ssoStatus: activeUsers.includes(emp.Emp_id) ? "Logged In" : "Offline",
		}));
	}, [empData, activeUsers]);

	const fetchEmpData = () => {
		setShowEmpDirectory(true);
		axios
			.get("https://sso.erldc.in:5000/emp_data", {
				headers: { Data: "Sanju8@92" },
			})
			.then((res) => {
				setEmpData(res.data);
			})
			.catch((err) => {
				console.error("Failed to fetch emp_data", err);
			});

		// Fetch currently logged-in SSO users if currentUserId is 00162
		const token = localStorage.getItem("token");
		try {
			const decoded = token ? jwt_decode(token) : {};
			if (decoded.User === "00162") {
				axios
					.get(`${SSO_API}/active-users`, {
						headers: { Token: token },
					})
					.then((res) => {
						setActiveUsers(res.data || []);
					})
					.catch((err) => {
						console.error("Failed to fetch active users", err);
					});
			}
		} catch (e) {
			console.error("Error checking user ID or fetching active users", e);
		}
	};

	const onGlobalFilterChange = (e) => {
		const value = e.target.value;
		let _filters = { ...filters };
		_filters["global"].value = value;
		setFilters(_filters);
		setGlobalFilterValue(value);
	};

	const header = (
		<div style={{ display: 'flex', justifyContent: 'flex-end' }}>
			<span className="p-input-icon-left">
				<i className="pi pi-search" />
				<InputText
					value={globalFilterValue}
					onChange={onGlobalFilterChange}
					placeholder="Search Personnel"
				/>
			</span>
		</div>
	);

	const saveWorkspaceData = (payload) => {
		const token = localStorage.getItem("token");
		axios.post(`${SSO_API}/workspace-data`, payload, {
			headers: { Token: token }
		}).catch((err) => {
			console.error("Failed to save workspace data", err);
		});
	};

	const onClickLogout = useCallback(() => {
		axios
			.post("https://sso.erldc.in:5000/logout", {
				headers: { token: localStorage["token"] },
			})
			.finally(() => {
				localStorage.removeItem("token");
				navigate("/");
			});
	}, [navigate]);

	useEffect(() => {
		const token = localStorage.getItem("token");

		if (!token) {
			navigate("/");
			return;
		}

		try {
			const decoded = jwt_decode(token);
			const tokenDate = new Date(decoded.Token_Time);
			const expiresAt = new Date(tokenDate.getTime() + SESSION_DURATION_MS);
			const sessionAgeInMs = new Date() - tokenDate;

			if (!decoded.Login) {
				localStorage.removeItem("token");
				navigate("/");
				return;
			}

			if (sessionAgeInMs > SESSION_DURATION_MS) {
				onClickLogout();
				return;
			}

			setUserDepartment(decoded.Department);
			setUserName(typeof decoded.Name === "string" ? decoded.Name : "");
			setCurrentUserId(decoded.User || "");
			setSessionExpiresAt(expiresAt);
			setIsCheckingSession(false);

			// Fetch workspace data from backend
			axios
				.get(`${SSO_API}/workspace-data`, {
					headers: { Token: token },
				})
				.then((res) => {
					const data = res.data;
					if (data) {
						if (data.custom_apps) setCustomApps(data.custom_apps);
						if (data.deleted_static_apps) setDeletedStaticTitles(data.deleted_static_apps);
						if (data.modified_static_apps) setModifiedStaticApps(data.modified_static_apps);
						if (data.custom_quick_links) setCustomQuickLinks(data.custom_quick_links);
					}
				})
				.catch((err) => {
					console.error("Failed to fetch workspace data", err);
				});

			// Fetch password expiry for this user (non-blocking)
			axios.post(`${SSO_API}/password-expiry`, {}, { headers: { Token: token } })
				.then(res => setPwdExpiry(res.data))
				.catch(() => { }); // silently ignore
		} catch (error) {
			localStorage.removeItem("token");
			navigate("/");
		}
	}, [navigate, onClickLogout]);

	useEffect(() => {
		const timerId = window.setInterval(() => {
			setNow(new Date());
		}, 1000);

		return () => window.clearInterval(timerId);
	}, []);

	useEffect(() => {
		if (!sessionExpiresAt || isCheckingSession) {
			return;
		}

		if (sessionExpiresAt.getTime() <= now.getTime()) {
			onClickLogout();
			return;
		}

		// Compute inline to avoid TDZ — remainingSessionSeconds useMemo is declared later
		const secsLeft = Math.max(0, Math.floor((sessionExpiresAt.getTime() - now.getTime()) / 1000));

		// Show warning modal when < SESSION_WARNING_THRESHOLD seconds remain
		if (secsLeft <= SESSION_WARNING_THRESHOLD && !sessionWarnedRef.current) {
			sessionWarnedRef.current = true;
			setShowSessionWarning(true);
		}
	}, [isCheckingSession, now, onClickLogout, sessionExpiresAt]);

	const categories = useMemo(
		() => ["All", ...Array.from(new Set(allApplications.map((app) => app.category)))],
		[allApplications]
	);

	const filteredApps = useMemo(() => {
		const normalizedQuery = query.trim().toLowerCase();

		return allApplications.filter((app) => {
			const categoryMatch =
				activeCategory === "All" || app.category === activeCategory;
			const queryMatch =
				!normalizedQuery ||
				[app.title, app.desc, app.category]
					.join(" ")
					.toLowerCase()
					.includes(normalizedQuery);

			return categoryMatch && queryMatch;
		});
	}, [activeCategory, query, allApplications]);

	const todayDate = useMemo(
		() =>
			new Intl.DateTimeFormat("en-IN", {
				weekday: "short",
				day: "2-digit",
				month: "short",
				year: "numeric",
			}).format(now),
		[now]
	);

	const currentTime = useMemo(
		() =>
			new Intl.DateTimeFormat("en-IN", {
				hour: "2-digit",
				minute: "2-digit",
				second: "2-digit",
				hour12: true,
			}).format(now),
		[now]
	);

	const remainingSessionSeconds = useMemo(() => {
		if (!sessionExpiresAt) {
			return 0;
		}

		return Math.max(
			0,
			Math.floor((sessionExpiresAt.getTime() - now.getTime()) / 1000)
		);
	}, [now, sessionExpiresAt]);

	const sessionCountdown = useMemo(
		() => formatCountdown(remainingSessionSeconds),
		[remainingSessionSeconds]
	);

	const sessionProgressPercent = useMemo(
		() => (remainingSessionSeconds / (SESSION_DURATION_MS / 1000)) * 100,
		[remainingSessionSeconds]
	);

	if (isCheckingSession) {
		return (
			<main className="dashboard-shell dashboard-shell--loading">
				<div className="portal-loader" role="status" aria-live="polite">
					<img src={GILogo} alt="Grid India" />
					<span />
					<p>Securing your ERLDC workspace</p>
				</div>
			</main>
		);
	}

	return (
		<main className="dashboard-shell">
			<nav className="dashboard-nav" aria-label="Portal navigation">
				<div className="dashboard-nav__brand">
					<img src={GILogo} alt="Grid India" />
					<span>ERLDC SSO</span>
				</div>
				<div className="dashboard-nav__actions">
					{userDepartment === "Information Technology (IT)" && (
						<>
							<button
								type="button"
								className="nav-dir-btn nav-admin-btn"
								onClick={() => navigate("/admin")}
							>
								<i className="pi pi-shield" aria-hidden="true" />
								<span>Admin Console</span>
							</button>
							<button
								type="button"
								className="nav-dir-btn"
								onClick={fetchEmpData}
							>
								<i className="pi pi-address-book" aria-hidden="true" />
								<span>Employee Directory</span>
							</button>
						</>
					)}
					<button
						type="button"
						className="nav-dir-btn nav-changepwd-btn"
						onClick={() => navigate("/reset-password")}
						title="Change your Active Directory password via OTP"
					>
						<i className="pi pi-key" aria-hidden="true" />
						<span>Change Password</span>
						{pwdExpiry && !pwdExpiry.never_expires && pwdExpiry.days_remaining !== null && pwdExpiry.days_remaining <= 7 && (
							<span className="nav-changepwd-badge">{pwdExpiry.days_remaining}d</span>
						)}
					</button>

					<a href="#applications">Applications</a>
					<a href="#quick-links">Quick Links</a>
					<Button
						className="dashboard-logout dashboard-logout--nav"
						icon="pi pi-sign-out"
						label="Logout"
						aria-label="Logout"
						onClick={onClickLogout}
					/>
				</div>
			</nav>

			<section className="dashboard-hero">
				<div className="dashboard-hero__content">
					<div className="dashboard-brand">
						<img src={GILogo} alt="Grid India" className="dashboard-brand__logo" />
						<div>
							<p className="dashboard-brand__eyebrow">ERLDC, Grid India</p>
							<h1>
								{typeof userName === "string" && userName
									? `Welcome, ${userName.split(" ")[0]}`
									: "Welcome to ERLDC Intranet"}
							</h1>
							<p className="dashboard-brand__copy">
								A secure launchpad for control room, metering, analytics, HRD,
								and stakeholder service applications.
							</p>
						</div>
					</div>

					<div className="dashboard-session">
						<span className="dashboard-session__pill">
							<i className="pi pi-shield" aria-hidden="true" />
							Session secured
						</span>
						<span className="dashboard-session__clock">
							<i className="pi pi-calendar" aria-hidden="true" />
							<span>{todayDate}</span>
							<strong>{currentTime}</strong>
						</span>
					</div>
				</div>

				<div className="dashboard-overview">
					<div>
						<span>{mappedApplications.length}</span>
						<p>Applications</p>
					</div>
					<div>
						<span>{allQuickLinks.length}</span>
						<p>Quick links</p>
					</div>
					<div
						className="dashboard-overview__session-card"
						style={{ "--session-progress": `${sessionProgressPercent}%` }}
					>
						<span className="dashboard-overview__countdown">
							<i className="pi pi-hourglass" aria-hidden="true" />
							{sessionCountdown}
						</span>
						<p>Session remaining</p>
					</div>
				</div>
			</section>

			{/* ── Password Expiry Banner ──────────────────────────────── */}
			{pwdExpiry && !pwdExpiry.never_expires && !pwdBannerDismissed &&
				pwdExpiry.days_remaining !== null && pwdExpiry.days_remaining <= 7 && (
					<div className={`dashboard-pwd-banner ${pwdExpiry.days_remaining <= 3 ? "dashboard-pwd-banner--critical" : ""}`} role="alert">
						<div className="dashboard-pwd-banner__icon">
							<i className={`pi ${pwdExpiry.days_remaining === 0 ? "pi-times-circle" : "pi-exclamation-triangle"}`} />
						</div>
						<div className="dashboard-pwd-banner__body">
							<strong>
								{pwdExpiry.days_remaining === 0
									? "Your password has expired!"
									: `Your password expires in ${pwdExpiry.days_remaining} day${pwdExpiry.days_remaining === 1 ? "" : "s"}.`}
							</strong>
							{" "}Reset it now to avoid being locked out of all ERLDC systems.
						</div>
						<button
							type="button"
							className="dashboard-pwd-banner__btn"
							onClick={() => navigate("/reset-password")}
						>
							<i className="pi pi-key" /> Reset Password
						</button>
						<button
							type="button"
							className="dashboard-pwd-banner__dismiss"
							aria-label="Dismiss"
							onClick={() => setPwdBannerDismissed(true)}
						>
							<i className="pi pi-times" />
						</button>
					</div>
				)}

			{/* ── Session Expiry Warning Modal ─────────────────────────── */}
			<Dialog
				visible={showSessionWarning}
				onHide={() => setShowSessionWarning(false)}
				className="session-warn-dialog"
				modal
				closable={false}
				header={(
					<div className="session-warn-header">
						<i className="pi pi-clock" />
						Session Expiring Soon
					</div>
				)}
				style={{ width: "min(440px, 92vw)" }}
			>
				<div className="session-warn-body">
					<div className="session-warn-countdown">{sessionCountdown}</div>
					<p>Your session will expire soon. Any unsaved work may be lost.</p>
					<div className="session-warn-actions">
						<button type="button" className="session-warn-btn session-warn-btn--stay"
							onClick={() => setShowSessionWarning(false)}>
							<i className="pi pi-check" /> Stay Logged In
						</button>
						<button type="button" className="session-warn-btn session-warn-btn--logout"
							onClick={onClickLogout}>
							<i className="pi pi-sign-out" /> Logout Now
						</button>
					</div>
				</div>
			</Dialog>

			<section className="dashboard-workspace">
				<div className="dashboard-toolbar">
					<div className="dashboard-search">
						<i className="pi pi-search" aria-hidden="true" />
						<input
							type="search"
							value={query}
							onChange={(event) => setQuery(event.target.value)}
							placeholder="Search applications"
							aria-label="Search applications"
						/>
					</div>

					<div className="category-tabs" aria-label="Application categories">
						{categories.map((category) => (
							<button
								type="button"
								key={category}
								className={
									activeCategory === category
										? "category-tab category-tab--active"
										: "category-tab"
								}
								onClick={() => setActiveCategory(category)}
							>
								{category}
							</button>
						))}
					</div>
				</div>

				<div className="section-heading" id="quick-links">
					<div>
						<p>Priority access</p>
						<h2>Quick Links</h2>
					</div>
					<span>{allQuickLinks.length} external portals</span>
				</div>

				<div className="quick-links" aria-label="Quick links">
					{allQuickLinks.map((link) => (
						<button
							type="button"
							key={link.label}
							className={`quick-link quick-link--${link.tone}`}
							onClick={() => window.open(link.url, "_blank", "noopener,noreferrer")}
						>
							<i className={link.icon} aria-hidden="true" />
							<span>{link.label}</span>
						</button>
					))}
					{userDepartment === "Information Technology (IT)" && (
						<button
							type="button"
							className="quick-link quick-link--add-placeholder"
							onClick={() => setShowAddQuickLinkDialog(true)}
						>
							<i className="pi pi-plus" aria-hidden="true" />
							<span>Add Link</span>
						</button>
					)}
				</div>

				<div className="section-heading" id="applications">
					<div>
						<p>Authorized workspace</p>
						<h2>Applications</h2>
					</div>
					<span>{filteredApps.length} visible</span>
				</div>

				<div className="app-grid" aria-live="polite">
					{filteredApps.map((app) => (
						<AppCard
							key={app.title}
							{...app}
							showAdminControls={currentUserId === "00162"}
							onEdit={() => handleStartEdit(app)}
							onDelete={() => handleDeleteApp(app)}
						/>
					))}
					{userDepartment === "Information Technology (IT)" && (
						<article 
							className="app-card app-card--add-placeholder"
							onClick={() => setShowAddAppDialog(true)}
						>
							<div className="app-card--add-placeholder__icon">
								<i className="pi pi-plus" />
							</div>
							<h3>Add Application</h3>
							<p>Register a new internal workspace link</p>
						</article>
					)}
				</div>

				{filteredApps.length === 0 && (
					<div className="dashboard-empty">
						<i className="pi pi-search" aria-hidden="true" />
						<p>No applications found</p>
					</div>
				)}

				<Dialog
					header={
						<div className="emp-dir-dialog-header">
							<span className="emp-dir-dialog-header__icon">
								<i className="pi pi-address-book" />
							</span>
							<div>
								<p className="emp-dir-dialog-header__eyebrow">ERLDC, Grid India</p>
								<h2 className="emp-dir-dialog-header__title">Employee Directory</h2>
							</div>
							{empData.length > 0 && (
								<span className="emp-dir-count-badge">
									{empData.length} Personnel
								</span>
							)}
						</div>
					}
					visible={showEmpDirectory}
					style={{ width: '88vw', maxWidth: '1280px', height: '100vh' }}
					maximizable
					modal
					className="emp-dir-dialog"
					onHide={() => setShowEmpDirectory(false)}
				>
					<DataTable
						filters={filters}
						globalFilterFields={["Name", "Emp_id", "Department", "Mail", "Mobile", "ssoStatus"]}
						header={
							<div className="emp-dir-table-toolbar">
								<span className="emp-dir-search-wrap">
									<i className="pi pi-search" />
									<InputText
										value={globalFilterValue}
										onChange={onGlobalFilterChange}
										placeholder="Search by name, ID, department, email…"
										className="emp-dir-search-input"
									/>
								</span>
							</div>
						}
						emptyMessage={
							<div className="emp-dir-empty">
								<i className="pi pi-search" />
								<p>No personnel match your search criteria.</p>
							</div>
						}
						rows={12}
						paginator
						rowsPerPageOptions={[10, 25, 50]}
						scrollable
						scrollHeight="flex"
						value={empTableData}
						stripedRows
						showGridlines
						className="emp-dir-table"
						sortMode="multiple"
					>
						<Column
							header="#"
							body={(_, opts) => <span className="emp-dir-row-num">{opts.rowIndex + 1}</span>}
							style={{ width: '3.5rem', textAlign: 'center' }}
						/>
						<Column
							field="Department"
							header="Department"
							style={{ width: '20%' }}
							sortable
							body={(rowData) => (
								<span className="emp-dir-dept-badge">{rowData.Department}</span>
							)}
						/>
						<Column
							field="Name"
							header="Employee Name"
							style={{ width: '20%' }}
							sortable
							body={(rowData) => (
								<span className="emp-dir-name">
									<i className="pi pi-user" />
									{rowData.Name}
								</span>
							)}
						/>
						<Column
							field="Emp_id"
							header="Employee ID"
							style={{ width: '12%' }}
							sortable
							body={(rowData) => (
								<code className="emp-dir-empid">{rowData.Emp_id}</code>
							)}
						/>
						<Column
							field="Mail"
							header="E-Mail Address"
							style={{ width: '25%' }}
							sortable
							body={(rowData) => (
								<a href={`mailto:${rowData.Mail}`} className="emp-dir-mail-link">
									<i className="pi pi-envelope" />
									{rowData.Mail}
								</a>
							)}
						/>
						<Column
							field="Mobile"
							header="Contact Number"
							style={{ width: '15%' }}
							body={(rowData) => (
								<span className="emp-dir-phone">
									<i className="pi pi-phone" />
									{rowData.Mobile}
								</span>
							)}
						/>
						{currentUserId === "00162" && (
							<Column
								field="ssoStatus"
								header="SSO Status"
								style={{ width: '12%', textAlign: 'center' }}
								sortable
								body={(rowData) => {
									const isOnline = rowData.ssoStatus === "Logged In";
									return (
										<span className={`emp-dir-status-badge emp-dir-status-badge--${isOnline ? 'online' : 'offline'}`}>
											<span className="emp-dir-status-badge__dot" />
											{rowData.ssoStatus}
										</span>
									);
								}}
							/>
						)}
					</DataTable>
				</Dialog>

				<Dialog
					visible={showAddAppDialog}
					onHide={() => setShowAddAppDialog(false)}
					className="add-app-dialog"
					modal
					header={
						<div className="add-app-dialog-header">
							<span className="add-app-dialog-header__icon">
								<i className="pi pi-plus" />
							</span>
							<div>
								<p className="add-app-dialog-header__eyebrow">IT Administrator Tools</p>
								<h2 className="add-app-dialog-header__title">Add Application Card</h2>
							</div>
						</div>
					}
					style={{ width: "min(500px, 92vw)" }}
				>
					<form onSubmit={handleAddApp} className="add-app-form">
						<div className="form-field">
							<label htmlFor="app-title">Application Title *</label>
							<InputText
								id="app-title"
								value={newAppTitle}
								onChange={(e) => setNewAppTitle(e.target.value)}
								placeholder="e.g. Weather Portal"
								required
							/>
						</div>

						<div className="form-field">
							<label htmlFor="app-desc">Short Description *</label>
							<InputText
								id="app-desc"
								value={newAppDesc}
								onChange={(e) => setNewAppDesc(e.target.value)}
								placeholder="e.g. Real-time weather monitoring system"
								required
							/>
						</div>

						<div className="form-field">
							<label htmlFor="app-url">URL *</label>
							<InputText
								id="app-url"
								value={newAppUrl}
								onChange={(e) => setNewAppUrl(e.target.value)}
								placeholder="e.g. https://weather.erldc.in"
								required
							/>
						</div>

						<div className="form-row">
							<div className="form-field">
								<label htmlFor="app-accent">Accent Color</label>
								<select
									id="app-accent"
									value={newAppAccent}
									onChange={(e) => setNewAppAccent(e.target.value)}
									className="form-select"
								>
									<option value="blue">Blue</option>
									<option value="green">Green</option>
									<option value="red">Red</option>
									<option value="amber">Amber</option>
									<option value="indigo">Indigo</option>
									<option value="violet">Violet</option>
									<option value="teal">Teal</option>
								</select>
							</div>

							<div className="form-field">
								<label htmlFor="app-icon">Icon</label>
								<select
									id="app-icon"
									value={newAppIcon}
									onChange={(e) => setNewAppIcon(e.target.value)}
									className="form-select"
								>
									<option value="pi pi-box">Box</option>
									<option value="pi pi-desktop">Desktop</option>
									<option value="pi pi-globe">Globe</option>
									<option value="pi pi-chart-bar">Chart Bar</option>
									<option value="pi pi-database">Database</option>
									<option value="pi pi-wrench">Wrench</option>
									<option value="pi pi-comments">Comments</option>
									<option value="pi pi-bolt">Bolt</option>
									<option value="pi pi-users">Users</option>
								</select>
							</div>
						</div>

						<div className="form-field">
							<label htmlFor="app-image">Image File Upload</label>
							<input
								type="file"
								id="app-image"
								accept="image/*"
								onChange={handleImageChange}
								className="form-file-input"
							/>
							{newAppImage && (
								<div className="form-image-preview">
									<img src={newAppImage} alt="Preview" />
									<button
										type="button"
										className="remove-preview-btn"
										onClick={() => setNewAppImage("")}
									>
										Remove Image
									</button>
								</div>
							)}
						</div>

						<div className="form-actions">
							<button
								type="button"
								className="form-btn form-btn--cancel"
								onClick={() => setShowAddAppDialog(false)}
							>
								Cancel
							</button>
							<button type="submit" className="form-btn form-btn--submit">
								Add Card
							</button>
						</div>
					</form>
				</Dialog>

				<Dialog
					visible={showEditAppDialog}
					onHide={() => setShowEditAppDialog(false)}
					className="add-app-dialog"
					modal
					header={
						<div className="add-app-dialog-header">
							<span className="add-app-dialog-header__icon">
								<i className="pi pi-pencil" />
							</span>
							<div>
								<p className="add-app-dialog-header__eyebrow">IT Administrator Tools</p>
								<h2 className="add-app-dialog-header__title">Modify Application Card</h2>
							</div>
						</div>
					}
					style={{ width: "min(500px, 92vw)" }}
				>
					<form onSubmit={handleSaveEdit} className="add-app-form">
						<div className="form-field">
							<label htmlFor="edit-app-title">Application Title *</label>
							<InputText
								id="edit-app-title"
								value={editAppTitle}
								onChange={(e) => setEditAppTitle(e.target.value)}
								placeholder="e.g. Weather Portal"
								required
							/>
						</div>

						<div className="form-field">
							<label htmlFor="edit-app-desc">Short Description *</label>
							<InputText
								id="edit-app-desc"
								value={editAppDesc}
								onChange={(e) => setEditAppDesc(e.target.value)}
								placeholder="e.g. Real-time weather monitoring system"
								required
							/>
						</div>

						<div className="form-field">
							<label htmlFor="edit-app-url">URL *</label>
							<InputText
								id="edit-app-url"
								value={editAppUrl}
								onChange={(e) => setEditAppUrl(e.target.value)}
								placeholder="e.g. https://weather.erldc.in"
								required
							/>
						</div>

						<div className="form-row">
							<div className="form-field">
								<label htmlFor="edit-app-accent">Accent Color</label>
								<select
									id="edit-app-accent"
									value={editAppAccent}
									onChange={(e) => setEditAppAccent(e.target.value)}
									className="form-select"
								>
									<option value="blue">Blue</option>
									<option value="green">Green</option>
									<option value="red">Red</option>
									<option value="amber">Amber</option>
									<option value="indigo">Indigo</option>
									<option value="violet">Violet</option>
									<option value="teal">Teal</option>
								</select>
							</div>

							<div className="form-field">
								<label htmlFor="edit-app-icon">Icon</label>
								<select
									id="edit-app-icon"
									value={editAppIcon}
									onChange={(e) => setEditAppIcon(e.target.value)}
									className="form-select"
								>
									<option value="pi pi-box">Box</option>
									<option value="pi pi-desktop">Desktop</option>
									<option value="pi pi-globe">Globe</option>
									<option value="pi pi-chart-bar">Chart Bar</option>
									<option value="pi pi-database">Database</option>
									<option value="pi pi-wrench">Wrench</option>
									<option value="pi pi-comments">Comments</option>
									<option value="pi pi-bolt">Bolt</option>
									<option value="pi pi-users">Users</option>
								</select>
							</div>
						</div>

						<div className="form-field">
							<label htmlFor="edit-app-image">Image File Upload</label>
							<input
								type="file"
								id="edit-app-image"
								accept="image/*"
								onChange={handleEditImageChange}
								className="form-file-input"
							/>
							{editAppImage && (
								<div className="form-image-preview">
									<img src={editAppImage} alt="Preview" />
									<button
										type="button"
										className="remove-preview-btn"
										onClick={() => setEditAppImage("")}
									>
										Remove Image
									</button>
								</div>
							)}
						</div>

						<div className="form-actions">
							<button
								type="button"
								className="form-btn form-btn--cancel"
								onClick={() => setShowEditAppDialog(false)}
							>
								Cancel
							</button>
							<button type="submit" className="form-btn form-btn--submit">
								Save Changes
							</button>
						</div>
					</form>
				</Dialog>

				<Dialog
					visible={showAddQuickLinkDialog}
					onHide={() => setShowAddQuickLinkDialog(false)}
					className="add-app-dialog"
					modal
					header={
						<div className="add-app-dialog-header">
							<span className="add-app-dialog-header__icon">
								<i className="pi pi-link" />
							</span>
							<div>
								<p className="add-app-dialog-header__eyebrow">IT Administrator Tools</p>
								<h2 className="add-app-dialog-header__title">Add Quick Link</h2>
							</div>
						</div>
					}
					style={{ width: "min(460px, 92vw)" }}
				>
					<form onSubmit={handleAddQuickLink} className="add-app-form">
						<div className="form-field">
							<label htmlFor="ql-label">Link Label *</label>
							<InputText
								id="ql-label"
								value={newQuickLinkLabel}
								onChange={(e) => setNewQuickLinkLabel(e.target.value)}
								placeholder="e.g. ERP System"
								required
							/>
						</div>

						<div className="form-field">
							<label htmlFor="ql-url">URL *</label>
							<InputText
								id="ql-url"
								value={newQuickLinkUrl}
								onChange={(e) => setNewQuickLinkUrl(e.target.value)}
								placeholder="e.g. https://erp.erldc.in"
								required
							/>
						</div>

						<div className="form-row">
							<div className="form-field">
								<label htmlFor="ql-tone">Color Tone</label>
								<select
									id="ql-tone"
									value={newQuickLinkTone}
									onChange={(e) => setNewQuickLinkTone(e.target.value)}
									className="form-select"
								>
									<option value="violet">Violet</option>
									<option value="teal">Teal</option>
									<option value="red">Red</option>
									<option value="green">Green</option>
									<option value="blue">Blue</option>
									<option value="amber">Amber</option>
									<option value="indigo">Indigo</option>
								</select>
							</div>

							<div className="form-field">
								<label htmlFor="ql-icon">Icon</label>
								<select
									id="ql-icon"
									value={newQuickLinkIcon}
									onChange={(e) => setNewQuickLinkIcon(e.target.value)}
									className="form-select"
								>
									<option value="pi pi-link">Link</option>
									<option value="pi pi-users">Users</option>
									<option value="pi pi-globe">Globe</option>
									<option value="pi pi-file-pdf">PDF Document</option>
									<option value="pi pi-desktop">Desktop</option>
									<option value="pi pi-lock-open">Lock Open</option>
									<option value="pi pi-ban">Ban</option>
									<option value="pi pi-eye">Eye</option>
									<option value="pi pi-database">Database</option>
									<option value="pi pi-file-edit">File Edit</option>
									<option value="pi pi-file-excel">Excel File</option>
								</select>
							</div>
						</div>

						<div className="form-actions">
							<button
								type="button"
								className="form-btn form-btn--cancel"
								onClick={() => setShowAddQuickLinkDialog(false)}
							>
								Cancel
							</button>
							<button type="submit" className="form-btn form-btn--submit">
								Add Link
							</button>
						</div>
					</form>
				</Dialog>
			</section>
		</main>
	);
}
